(() => {
  const canvas = document.getElementById("background");
  if (!canvas) return;
  const ctx = canvas.getContext("2d");
  if (!ctx) return;

  const DPR = Math.min(window.devicePixelRatio || 1, 2);
  let width = 0;
  let height = 0;
  let rafId = 0;
  let meteorCooldown = 0;
  const stars = [];
  const meteors = [];

  const rand = (min, max) => Math.random() * (max - min) + min;

  const resize = () => {
    width = window.innerWidth;
    height = window.innerHeight;
    canvas.width = Math.floor(width * DPR);
    canvas.height = Math.floor(height * DPR);
    canvas.style.width = `${width}px`;
    canvas.style.height = `${height}px`;
    ctx.setTransform(DPR, 0, 0, DPR, 0, 0);

    stars.length = 0;
    const count = Math.max(36, Math.floor(width * height / 32000));
    for (let i = 0; i < count; i += 1) {
      stars.push({
        x: rand(0, width),
        y: rand(0, height),
        r: rand(0.45, 1.35),
        alpha: rand(0.12, 0.52),
        phase: rand(0, Math.PI * 2),
        speed: rand(0.003, 0.01),
      });
    }
  };

  const spawnMeteor = () => {
    meteors.push({
      x: rand(width * 0.25, width * 0.95),
      y: rand(-80, height * 0.18),
      vx: rand(-10.5, -8.2),
      vy: rand(6.4, 8.1),
      length: rand(120, 200),
      width: rand(0.9, 1.6),
      age: 0,
      ttl: rand(26, 38),
    });
  };

  const drawDeepSpace = () => {
    const bg = ctx.createLinearGradient(0, 0, 0, height);
    bg.addColorStop(0, "rgba(3, 8, 18, 0.72)");
    bg.addColorStop(0.5, "rgba(5, 12, 28, 0.44)");
    bg.addColorStop(1, "rgba(8, 18, 38, 0.22)");
    ctx.fillStyle = bg;
    ctx.fillRect(0, 0, width, height);

    const halo = ctx.createRadialGradient(
      width * 0.52,
      height * 0.3,
      0,
      width * 0.52,
      height * 0.3,
      Math.max(width, height) * 0.65
    );
    halo.addColorStop(0, "rgba(70, 120, 200, 0.12)");
    halo.addColorStop(0.4, "rgba(40, 75, 140, 0.06)");
    halo.addColorStop(1, "rgba(8, 16, 34, 0)");
    ctx.fillStyle = halo;
    ctx.fillRect(0, 0, width, height);
  };

  const drawStars = () => {
    for (const star of stars) {
      star.phase += star.speed;
      const alpha = star.alpha + Math.sin(star.phase) * 0.08;
      ctx.beginPath();
      ctx.fillStyle = `rgba(210, 228, 255, ${Math.max(0.06, alpha)})`;
      ctx.arc(star.x, star.y, star.r, 0, Math.PI * 2);
      ctx.fill();
    }
  };

  const drawMeteors = () => {
    for (let i = meteors.length - 1; i >= 0; i -= 1) {
      const m = meteors[i];
      m.age += 1;
      m.x += m.vx;
      m.y += m.vy;

      const alpha = Math.max(0, 1 - m.age / m.ttl);
      const tailX = m.x + m.length;
      const tailY = m.y - m.length * 0.68;

      const gradient = ctx.createLinearGradient(m.x, m.y, tailX, tailY);
      gradient.addColorStop(0, `rgba(210, 234, 255, ${0.78 * alpha})`);
      gradient.addColorStop(0.35, `rgba(116, 184, 255, ${0.42 * alpha})`);
      gradient.addColorStop(1, "rgba(116, 184, 255, 0)");

      ctx.strokeStyle = gradient;
      ctx.lineWidth = m.width;
      ctx.beginPath();
      ctx.moveTo(m.x, m.y);
      ctx.lineTo(tailX, tailY);
      ctx.stroke();

      if (m.age >= m.ttl || m.x < -m.length || m.y > height + m.length) {
        meteors.splice(i, 1);
      }
    }
  };

  const frame = () => {
    ctx.clearRect(0, 0, width, height);
    drawDeepSpace();
    drawStars();
    drawMeteors();

    meteorCooldown -= 1;
    if (meteorCooldown <= 0) {
      if (Math.random() > 0.6) spawnMeteor();
      meteorCooldown = rand(70, 150);
    }

    rafId = requestAnimationFrame(frame);
  };

  const start = () => {
    cancelAnimationFrame(rafId);
    resize();
    frame();
  };

  window.addEventListener("resize", resize);
  document.addEventListener("visibilitychange", () => {
    if (document.hidden) {
      cancelAnimationFrame(rafId);
      return;
    }
    frame();
  });

  start();
})();
